mapper.select:
select id, url, cover_url, description, likes, comments, favorites, created_time from video where creator_id = #{userId} and status = 'PUBLISHED'
and id < #{lastMinId}
order by id desc limit 10;

select id, url, cover_url, description, likes, comments, favorites, created_time from video where creator_id = #{userId} and status = 'PROCESSING'
and id < #{lastMinId}
order by id desc limit 10

select id, url, cover_url, description, likes, comments, favorites, created_time from video where creator_id = #{userId} and status = 'REJECTED'
and id < #{lastMinId}
order by id desc limit 10

select l.id as like_id, video.id as video_id, creator_id, url, cover_url, description, likes from video join ( select id, video_id from video_user_like where user_id = #{userId}
and id < #{lastMinId}
order by id desc limit 10 ) l on video.id = l.video_id order by l.id desc

select f.id as favorite_id, video.id as video_id, creator_id, url, cover_url, description, favorites from video join ( select id, video_id from video_user_favorite where user_id = #{userId}
and id < #{lastMinId}
order by id desc limit 10 ) f on video.id = f.video_id order by f.id desc
